sql:
SELECT complex_name
FROM complexes
WHERE complex_id = 1;

SELECT annotation_name
FROM protein_annotations
WHERE annotation_value = 'High' AND protein_id = 1;

SELECT protein_id
FROM proteins
WHERE protein_id = 'protein_id_value';

SELECT proteins.protein_name, protein_ligand_interactions.binding_affinity
FROM proteins
LEFT JOIN protein_ligand_interactions ON proteins.protein_id = protein_ligand_interactions.protein_id;

SELECT COUNT(DISTINCT p.pdb_id)
FROM proteins p
JOIN access_logs a ON p.protein_id = a.protein_id;

SELECT protein_name 
FROM proteins 
WHERE molecular_weight > (SELECT AVG(molecular_weight) FROM proteins);

SELECT complex_id, annotation_value 
FROM complex_annotations 
WHERE source = 'PANTHER' AND annotation_name = 'PTHR12345';

external_knowledge:
- 'sea of proteins' refers to the collection of proteins;
- 'treasure map' is a metaphor for the unique identifier 'pdb_id' that points to a specific protein;
- 'travelers' and 'sailed' refer to users and their access actions to the protein, respectively;
- 'voyages' represent the number of times each user has accessed the protein.

- "above-average molecular weight" refers to proteins with a molecular weight greater than 50000;
- "moderate isoelectric point" means the protein's isoelectric point is between 6 and 8;
- "strong labels" imply complexes whose labels have a value greater than 0.7;
- "low affinity" indicates that the binding affinity of the binding site is less than 10;
- "specific annotations starting with 'Pfam'" refers to annotations whose names begin with the prefix "Pfam";
- "PDB ID" is the unique identifier for a protein structure in the Protein Data Bank.

- Stars of the celestial dance: refers to complexes and proteins in the scientific context;
- Cosmic structure: refers to the fold structure of the protein;
- Constellation: used metaphorically to refer to proteins with a specific PDB ID;
- PDB ID '4JPK': a specific identifier for a protein structure;

sql:
SELECT binding_site_id, binding_site_name
FROM binding_sites
WHERE binding_affinity > 2;

SELECT fold_name 
FROM fold_ids 
WHERE complex_id = 1;

SELECT protein_name, molecular_weight, isoelectric_point
FROM proteins
WHERE molecular_weight = (SELECT MAX(molecular_weight) FROM proteins);

SELECT binding_affinity
FROM protein_ligand_interactions
WHERE protein_id = 1 AND ligand_id = 0;

SELECT DISTINCT protein_id
FROM protein_annotations
WHERE annotation_value = 'active';

SELECT p.protein_name, p.protein_id, pa.annotation_name, pa.annotation_value, pa.source
FROM proteins p
JOIN protein_annotations pa ON p.protein_id = pa.protein_id;

SELECT chain_id 
FROM chains 
WHERE sequence_identity > 95;

SELECT interaction_type 
FROM protein_interactions 
WHERE (protein1_id = 0 AND protein2_id = 1) OR (protein1_id = 1 AND protein2_id = 0);
